func newAnalyticsCmd(flags *rootFlags) *cobra.Command {
	var resourceType string
	var groupBy string
	var dbPath string
	var limit int

	cmd := &cobra.Command{
		Use:   "analytics",
		Short: "Run analytics queries on locally synced data",
		Long: `Analyze locally synced data with count, group-by, and summary operations.
Data must be synced first with the sync command.`,
		Example: `  # Count records by type
  dominos-pp-cli analytics --type messages

  # Group by a field
  dominos-pp-cli analytics --type messages --group-by author_id

  # Show a local analytics dashboard
  dominos-pp-cli analytics summary

  # Most frequently ordered product codes
  dominos-pp-cli analytics popular --limit 10

  # Spending insights from locally stored orders
  dominos-pp-cli analytics spending --json`,
		RunE: func(cmd *cobra.Command, args []string) error {
			db, err := openAnalyticsDB(dbPath)
			if err != nil {
				return err
			}
			defer db.Close()

			if resourceType == "" {
				// Show summary of all resource types
				status, err := db.Status()
				if err != nil {
					return fmt.Errorf("getting status: %w", err)
				}
				if flags.asJSON {
					enc := json.NewEncoder(os.Stdout)
					enc.SetIndent("", "  ")
					return enc.Encode(status)
				}
				fmt.Println("Resource Type\tCount")
				fmt.Println("-------------\t-----")
				for rt, count := range status {
					fmt.Printf("%s\t%d\n", rt, count)
				}
				return nil
			}

			if groupBy != "" {
				return runGroupBy(db, resourceType, groupBy, limit, flags)
			}

			count, err := db.Count(resourceType)
			if err != nil {
				return fmt.Errorf("counting: %w", err)
			}

			if flags.asJSON {
				result := map[string]any{"resource_type": resourceType, "count": count}
				enc := json.NewEncoder(os.Stdout)
				enc.SetIndent("", "  ")
				return enc.Encode(result)
			}

			fmt.Printf("%s: %d records\n", resourceType, count)
			return nil
		},
	}

	cmd.PersistentFlags().StringVar(&dbPath, "db", "", "Database path")
	cmd.PersistentFlags().IntVar(&limit, "limit", 25, "Max groups to show")
	cmd.Flags().StringVar(&resourceType, "type", "", "Resource type to analyze")
	cmd.Flags().StringVar(&groupBy, "group-by", "", "Field to group by")
	cmd.AddCommand(newAnalyticsSummaryCmd(flags, &dbPath, &limit))
	cmd.AddCommand(newAnalyticsPopularCmd(flags, &dbPath, &limit))
	cmd.AddCommand(newAnalyticsSpendingCmd(flags, &dbPath, &limit))

	return cmd
}

func runGroupBy(db *store.Store, resourceType, field string, limit int, flags *rootFlags) error {
	items, err := db.List(resourceType, 0)
	if err != nil {
		return err
	}

	counts := make(map[string]int)
	for _, item := range items {
		var obj map[string]any
		if err := json.Unmarshal(item, &obj); err != nil {
			continue
		}
		val := fmt.Sprintf("%v", obj[field])
		counts[val]++
	}

	type kv struct {
		Key   string `json:"value"`
		Count int    `json:"count"`
	}
	var sorted []kv
	for k, v := range counts {
		sorted = append(sorted, kv{k, v})
	}
	sort.Slice(sorted, func(i, j int) bool { return sorted[i].Count > sorted[j].Count })
	if limit > 0 && len(sorted) > limit {
		sorted = sorted[:limit]
	}

	if flags.asJSON {
		enc := json.NewEncoder(os.Stdout)
		enc.SetIndent("", "  ")
		return enc.Encode(sorted)
	}

	fmt.Printf("%s\tCount\n", field)
	fmt.Println("---\t-----")
	for _, kv := range sorted {
		fmt.Printf("%s\t%d\n", kv.Key, kv.Count)
	}
	return nil
}

func newAnalyticsSummaryCmd(flags *rootFlags, dbPath *string, _ *int) *cobra.Command {
	return &cobra.Command{
		Use:   "summary",
		Short: "Show a dashboard of local Domino's data",
		RunE: func(cmd *cobra.Command, args []string) error {
			db, err := openAnalyticsDB(*dbPath)
			if err != nil {
				return err
			}
			defer db.Close()

			status, err := db.Status()
			if err != nil {
				return fmt.Errorf("getting status: %w", err)
			}

			queries := []struct {
				key   string
				label string
				sql   string
			}{
				{"stores", "Stores synced", `SELECT COUNT(*) FROM stores`},
				{"menu_items", "Menu items cached", `SELECT COUNT(*) FROM menu_items`},
				{"carts", "Carts saved", `SELECT COUNT(*) FROM carts`},
				{"order_templates", "Templates saved", `SELECT COUNT(*) FROM order_templates`},
				{"deals", "Deals cached", `SELECT COUNT(*) FROM deals`},
				{"addresses", "Addresses saved", `SELECT COUNT(*) FROM addresses`},
			}
			out := map[string]any{"resources": status}
			rows := make([][2]any, 0, len(queries))
			for _, q := range queries {
				count, err := queryCount(db, q.sql)
				if err != nil {
					return err
				}
				out[q.key] = count
				rows = append(rows, [2]any{q.label, count})
			}

			if flags.asJSON {
				return writeAnalyticsJSON(out)
			}
			fmt.Println("Local Data Summary")
			for _, row := range rows {
				fmt.Printf("%-18s %v\n", row[0], row[1])
			}
			if len(status) > 0 {
				keys := make([]string, 0, len(status))
				for k := range status {
					keys = append(keys, k)
				}
				sort.Strings(keys)
				fmt.Println("\nSynced resources")
				for _, k := range keys {
					fmt.Printf("%-18s %d\n", k, status[k])
				}
			}
			return nil
		},
	}
}

func newAnalyticsPopularCmd(flags *rootFlags, dbPath *string, limit *int) *cobra.Command {
	type popularRow struct {
		Code        string `json:"product_code"`
		Count       int    `json:"count"`
		LastOrdered string `json:"last_ordered"`
	}
	return &cobra.Command{
		Use:   "popular",
		Short: "Show the most frequently ordered product codes",
		RunE: func(cmd *cobra.Command, args []string) error {
			db, err := openAnalyticsDB(*dbPath)
			if err != nil {
				return err
			}
			defer db.Close()

			counts := map[string]*popularRow{}
			sources := []struct {
				sql string
				col string
			}{
				{`SELECT items_json, COALESCE(updated_at, created_at, '') FROM carts`, "carts"},
				{`SELECT items_json, COALESCE(created_at, '') FROM order_templates`, "order_templates"},
			}
			for _, src := range sources {
				rows, err := db.Query(src.sql)
				if err != nil {
					return fmt.Errorf("querying %s: %w", src.col, err)
				}
				for rows.Next() {
					var itemsJSON, ts string
					if err := rows.Scan(&itemsJSON, &ts); err != nil {
						rows.Close()
						return err
					}
					for _, code := range extractProductCodes(itemsJSON) {
						entry := counts[code]
						if entry == nil {
							entry = &popularRow{Code: code, LastOrdered: ts}
							counts[code] = entry
						}
						entry.Count++
						if ts > entry.LastOrdered {
							entry.LastOrdered = ts
						}
					}
				}
				if err := rows.Err(); err != nil {
					rows.Close()
					return err
				}
				rows.Close()
			}

			if len(counts) == 0 {
				return printNoData(flags)
			}

			out := make([]popularRow, 0, len(counts))
			for _, row := range counts {
				out = append(out, *row)
			}
			sort.Slice(out, func(i, j int) bool {
				if out[i].Count == out[j].Count {
					return out[i].LastOrdered > out[j].LastOrdered
				}
				return out[i].Count > out[j].Count
			})
			if *limit > 0 && len(out) > *limit {
				out = out[:*limit]
			}

			if flags.asJSON {
				return writeAnalyticsJSON(out)
			}
			fmt.Println("PRODUCT CODE\tCOUNT\tLAST ORDERED")
			for _, row := range out {
				fmt.Printf("%s\t%d\t%s\n", row.Code, row.Count, row.LastOrdered)
			}
			return nil
		},
	}
}

func newAnalyticsSpendingCmd(flags *rootFlags, dbPath *string, _ *int) *cobra.Command {
	return &cobra.Command{
		Use:   "spending",
		Short: "Show spending insights from locally stored orders",
		RunE: func(cmd *cobra.Command, args []string) error {
			db, err := openAnalyticsDB(*dbPath)
			if err != nil {
				return err
			}
			defer db.Close()

			rows, err := db.Query(`SELECT data FROM orders`)
			if err != nil {
				return fmt.Errorf("querying orders: %w", err)
			}
			defer rows.Close()

			totalOrders, pricedOrders := 0, 0
			totalSpent, mostExpensive := 0.0, 0.0
			addressCounts := map[string]int{}
			for rows.Next() {
				var raw string
				if err := rows.Scan(&raw); err != nil {
					return err
				}
				totalOrders++
				if total, ok := extractOrderTotal(json.RawMessage(raw)); ok {
					pricedOrders++
					totalSpent += total
					if total > mostExpensive {
						mostExpensive = total
					}
				}
				if addr := extractOrderAddress(json.RawMessage(raw)); addr != "" {
					addressCounts[addr]++
				}
			}
			if err := rows.Err(); err != nil {
				return err
			}
			if totalOrders == 0 {
				return printNoData(flags)
			}

			mostCommonAddress, mostCommonCount := "", 0
			for addr, count := range addressCounts {
				if count > mostCommonCount {
					mostCommonAddress, mostCommonCount = addr, count
				}
			}
			avg := 0.0
			if pricedOrders > 0 {
				avg = totalSpent / float64(pricedOrders)
			}
			out := map[string]any{
				"total_orders":             totalOrders,
				"priced_orders":            pricedOrders,
				"total_spent":              totalSpent,
				"average_order_value":      avg,
				"most_expensive_order":     mostExpensive,
				"most_common_address":      mostCommonAddress,
				"most_common_address_uses": mostCommonCount,
			}
			if flags.asJSON {
				return writeAnalyticsJSON(out)
			}
			fmt.Printf("Total orders placed: %d\n", totalOrders)
			fmt.Printf("Total spent: %.2f\n", totalSpent)
			fmt.Printf("Average order value: %.2f\n", avg)
			fmt.Printf("Most expensive order: %.2f\n", mostExpensive)
			if mostCommonAddress == "" {
				fmt.Println("Most common delivery address: n/a")
			} else {
				fmt.Printf("Most common delivery address: %s (%d)\n", mostCommonAddress, mostCommonCount)
			}
			return nil
		},
	}
}

func openAnalyticsDB(dbPath string) (*store.Store, error) {
	if dbPath == "" {
		home, _ := os.UserHomeDir()
		dbPath = filepath.Join(home, ".local", "share", "dominos-pp-cli", "data.db")
	}
	db, err := store.Open(dbPath)
	if err != nil {
		return nil, fmt.Errorf("opening local database: %w\nRun 'dominos-pp-cli sync' first.", err)
	}
	return db, nil
}

func writeAnalyticsJSON(v any) error {
	enc := json.NewEncoder(os.Stdout)
	enc.SetIndent("", "  ")
	return enc.Encode(v)
}

func printNoData(flags *rootFlags) error {
	msg := map[string]any{"message": "No data yet. Run commands to populate."}
	if flags.asJSON {
		return writeAnalyticsJSON(msg)
	}
	fmt.Println(msg["message"])
	return nil
}

func queryCount(db *store.Store, query string, args ...any) (int, error) {
	rows, err := db.Query(query, args...)
	if err != nil {
		return 0, fmt.Errorf("running count query: %w", err)
	}
	defer rows.Close()
	var count int
	if rows.Next() {
		if err := rows.Scan(&count); err != nil {
			return 0, err
		}
	}
	return count, rows.Err()
}

func extractProductCodes(itemsJSON string) []string {
	var items []map[string]any
	if json.Unmarshal([]byte(itemsJSON), &items) != nil {
		return nil
	}
	out := make([]string, 0, len(items))
	for _, item := range items {
		code := strings.ToUpper(strings.TrimSpace(pickS(item, "code", "product_code", "productCode")))
		if code != "" {
			out = append(out, code)
		}
	}
	return out
}

func extractOrderTotal(data json.RawMessage) (float64, bool) {
	best := -1.0
	for _, m := range findMaps(data) {
		for _, key := range []string{"grand_total", "grandTotal", "order_total", "orderTotal", "customer", "amount", "Amount", "price", "Price", "total", "Total"} {
			if v, ok := numericValue(m[key]); ok && v > best {
				best = v
			}
		}
	}
	return best, best >= 0
}

func extractOrderAddress(data json.RawMessage) string {
	for _, m := range findMaps(data) {
		addr := strings.TrimSpace(strings.Join([]string{
			pickS(m, "street", "Street", "street1", "streetAddress"),
			pickS(m, "city", "City"),
			pickS(m, "state", "State", "region"),
			pickS(m, "zip", "postalCode", "PostalCode"),
		}, " "))
		addr = strings.Join(strings.Fields(strings.ReplaceAll(addr, ",", " ")), " ")
		if addr != "" {
			return addr
		}
	}
	return ""
}

func numericValue(v any) (float64, bool) {
	switch t := v.(type) {
	case float64:
		return t, true
	case string:
		if strings.TrimSpace(t) == "" {
			return 0, false
		}
		return parsePrice(t), true
	default:
		return 0, false
	}
}
